| Stack (after movem 48 bytes): 52=screen, 56=tileSolid, 60=tileDeco, 64=scrolls
| ============================================================
        .global ParallaxDrawAsm
ParallaxDrawAsm:
        movem.l d0-d7/a0-a5,-(sp)      | 12 regs = 48 bytes
    442e:	movem.l d0-a5,-(sp)

        move.l  52(sp),a0               | a0 = screen_mem (plane 0 base)
    4432:	movea.l 52(sp),a0
        move.l  56(sp),a2               | a2 = tileSolid
    4436:	movea.l 56(sp),a2
        move.l  60(sp),a3               | a3 = tileDeco
    443a:	movea.l 60(sp),a3
        move.l  64(sp),a4               | a4 = scrolls
    443e:	movea.l 64(sp),a4

        | --- PLANE 1: bytes 0-3 = 0, bytes 32-35 = 0 (256 rows) ---
        move.l  a0,a1
    4442:	movea.l a0,a1
        lea     10240(a1),a1            | a1 = plane 1
    4444:	lea 10240(a1),a1
        move.w  #255,d0
    4448:	move.w #255,d0

0000444c <.pd_p1>:
.pd_p1:
        clr.l   (a1)                    | bytes 0-3 = 0
    444c:	,-> clr.l (a1)
        clr.l   32(a1)                  | bytes 32-35 = 0
    444e:	|   clr.l 32(a1)
        lea     40(a1),a1
    4452:	|   lea 40(a1),a1
        dbra    d0,.pd_p1
    4456:	'-- dbf d0,444c <.pd_p1>

        | --- PLANES 2,3,4: bytes 0-3 = FF, bytes 32-35 = FF ---
        | a1 is now at plane 2 base
        moveq   #2,d1                   | 3 planes
    445a:	    moveq #2,d1

0000445c <.pd_hp_plane>:
.pd_hp_plane:
        move.w  #255,d0
    445c:	move.w #255,d0

00004460 <.pd_hp_row>:
.pd_hp_row:
        move.l  #0xFFFFFFFF,(a1)        | bytes 0-3
    4460:	,-> move.l #-1,(a1)
        move.l  #0xFFFFFFFF,32(a1)      | bytes 32-35
    4466:	|   move.l #-1,32(a1)
        lea     40(a1),a1
    446e:	|   lea 40(a1),a1
        dbra    d0,.pd_hp_row
    4472:	'-- dbf d0,4460 <.pd_hp_row>
        dbra    d1,.pd_hp_plane
    4476:	    dbf d1,445c <.pd_hp_plane>

        | --- PLANE 0: tile pattern ---
        | Load biased scroll values: bias = 256 - scroll (so index = (row+bias) & 63)
        move.w  (a4),d4
    447a:	    move.w (a4),d4
        neg.w   d4
    447c:	    neg.w d4
        addi.w  #256,d4                 | d4 = bias0
    447e:	    addi.w #256,d4
        move.w  2(a4),d5
    4482:	    move.w 2(a4),d5
        neg.w   d5
    4486:	    neg.w d5
        addi.w  #256,d5                 | d5 = bias1
    4488:	    addi.w #256,d5
        move.w  4(a4),d6
    448c:	    move.w 4(a4),d6
        neg.w   d6
    4490:	    neg.w d6
        addi.w  #256,d6                 | d6 = bias2
    4492:	    addi.w #256,d6
        move.w  6(a4),d7
    4496:	    move.w 6(a4),d7
        neg.w   d7
    449a:	    neg.w d7
        addi.w  #256,d7                 | d7 = bias3
    449c:	    addi.w #256,d7

        move.l  a0,a1                   | a1 = plane 0 base
    44a0:	    movea.l a0,a1
        move.w  #255,d3                 | 256 rows
    44a2:	    move.w #255,d3
        moveq   #0,d0                   | row = 0
    44a6:	    moveq #0,d0

000044a8 <.pd_p0_row>:

.pd_p0_row:
        | t3 index -> tileSolid[t3]
        move.w  d0,d1
    44a8:	,-> move.w d0,d1
        add.w   d7,d1
    44aa:	|   add.w d7,d1
        andi.w  #63,d1
    44ac:	|   andi.w #63,d1
        add.w   d1,d1                   | word offset
    44b0:	|   add.w d1,d1
        move.w  (a2,d1.w),d2           | d2 = tileSolid[t3]
    44b2:	|   move.w (0,a2,d1.w),d2
        | byte 0 = high byte, byte 35 = low byte
        move.b  d2,35(a1)
    44b6:	|   move.b d2,35(a1)
        lsr.w   #8,d2
    44ba:	|   lsr.w #8,d2
        move.b  d2,(a1)
    44bc:	|   move.b d2,(a1)

        | t2 index -> tileDeco[t2]
        move.w  d0,d1
    44be:	|   move.w d0,d1
        add.w   d6,d1
    44c0:	|   add.w d6,d1
        andi.w  #63,d1
    44c2:	|   andi.w #63,d1
        add.w   d1,d1
    44c6:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t2]
    44c8:	|   move.w (0,a3,d1.w),d2
        | byte 1 = low byte, byte 34 = high byte
        move.b  d2,1(a1)
    44cc:	|   move.b d2,1(a1)
        lsr.w   #8,d2
    44d0:	|   lsr.w #8,d2
        move.b  d2,34(a1)
    44d2:	|   move.b d2,34(a1)

        | t1 index -> tileDeco[t1]
        move.w  d0,d1
    44d6:	|   move.w d0,d1
        add.w   d5,d1
    44d8:	|   add.w d5,d1
        andi.w  #63,d1
    44da:	|   andi.w #63,d1
        add.w   d1,d1
    44de:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t1]
    44e0:	|   move.w (0,a3,d1.w),d2
        | byte 2 = high byte, byte 33 = low byte
        move.b  d2,33(a1)
    44e4:	|   move.b d2,33(a1)
        lsr.w   #8,d2
    44e8:	|   lsr.w #8,d2
        move.b  d2,2(a1)
    44ea:	|   move.b d2,2(a1)

        | t0 index -> tileDeco[t0]
        move.w  d0,d1
    44ee:	|   move.w d0,d1
        add.w   d4,d1
    44f0:	|   add.w d4,d1
        andi.w  #63,d1
    44f2:	|   andi.w #63,d1
        add.w   d1,d1
    44f6:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t0]
    44f8:	|   move.w (0,a3,d1.w),d2
        | byte 3 = low byte, byte 32 = high byte
        move.b  d2,3(a1)
    44fc:	|   move.b d2,3(a1)
        lsr.w   #8,d2
    4500:	|   lsr.w #8,d2
        move.b  d2,32(a1)
    4502:	|   move.b d2,32(a1)

        lea     40(a1),a1              | next row
    4506:	|   lea 40(a1),a1
        addq.w  #1,d0
    450a:	|   addq.w #1,d0
        dbra    d3,.pd_p0_row
    450c:	'-- dbf d3,44a8 <.pd_p0_row>

        movem.l (sp)+,d0-d7/a0-a5
    4510:	    movem.l (sp)+,d0-a5
        rts
    4514:	    rts

00004516 <ClearAndParallaxAsm>:
| Combined clear + parallax wall draw, single pass per plane.
| Stack (after movem 56 bytes): 60=screen, 64=tileSolid, 68=tileDeco, 72=scrolls
| ============================================================
        .global ClearAndParallaxAsm
ClearAndParallaxAsm:
        movem.l d0-d7/a0-a6,-(sp)
    4516:	movem.l d0-a6,-(sp)

        move.l  60(sp),a0               | a0 = screen_mem
    451a:	movea.l 60(sp),a0
        move.l  64(sp),a2               | a2 = tileSolid
    451e:	movea.l 64(sp),a2
        move.l  68(sp),a3               | a3 = tileDeco
    4522:	movea.l 68(sp),a3
        move.l  72(sp),a4               | a4 = scrolls ptr
    4526:	movea.l 72(sp),a4

        | Precompute biased scroll values (256 - scroll) for easy index calc
        move.w  (a4),d4
    452a:	move.w (a4),d4
        neg.w   d4
    452c:	neg.w d4
        addi.w  #256,d4                 | d4 = bias0
    452e:	addi.w #256,d4
        move.w  2(a4),d5
    4532:	move.w 2(a4),d5
        neg.w   d5
    4536:	neg.w d5
        addi.w  #256,d5                 | d5 = bias1
    4538:	addi.w #256,d5
        move.w  4(a4),d6
    453c:	move.w 4(a4),d6
        neg.w   d6
    4540:	neg.w d6
        addi.w  #256,d6                 | d6 = bias2
    4542:	addi.w #256,d6
        move.w  6(a4),d7
    4546:	move.w 6(a4),d7
        neg.w   d7
    454a:	neg.w d7
        addi.w  #256,d7                 | d7 = bias3
    454c:	addi.w #256,d7

| ---- PLANE 0: tile pattern + clear middle ----
        move.l  a0,a1                   | a1 = plane0 ptr (advances per row)
    4550:	movea.l a0,a1
        move.w  #255,d3                 | 256 rows
    4552:	move.w #255,d3
        moveq   #0,d0                   | row counter
    4556:	moveq #0,d0

00004558 <.cp0_row>:
.cp0_row:
        | tile indices -> tile bytes
        | t3: byte0=tileSolid[t3]>>8, byte35=tileSolid[t3]&FF
        move.w  d0,d1
    4558:	,-> move.w d0,d1
        add.w   d7,d1
