        andi.w  #63,d1
    455c:	|   andi.w #63,d1
        add.w   d1,d1
    4560:	|   add.w d1,d1
        move.w  (a2,d1.w),d2           | d2 = tileSolid[t3]
    4562:	|   move.w (0,a2,d1.w),d2
        move.b  d2,35(a1)             | byte35 = low byte
    4566:	|   move.b d2,35(a1)
        lsr.w   #8,d2
    456a:	|   lsr.w #8,d2
        move.b  d2,(a1)               | byte0 = high byte
    456c:	|   move.b d2,(a1)

        | t2: byte1=tileDeco[t2]&FF, byte34=tileDeco[t2]>>8
        move.w  d0,d1
    456e:	|   move.w d0,d1
        add.w   d6,d1
    4570:	|   add.w d6,d1
        andi.w  #63,d1
    4572:	|   andi.w #63,d1
        add.w   d1,d1
    4576:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t2]
    4578:	|   move.w (0,a3,d1.w),d2
        move.b  d2,1(a1)              | byte1 = low byte
    457c:	|   move.b d2,1(a1)
        lsr.w   #8,d2
    4580:	|   lsr.w #8,d2
        move.b  d2,34(a1)             | byte34 = high byte
    4582:	|   move.b d2,34(a1)

        | t1: byte2=tileDeco[t1]>>8, byte33=tileDeco[t1]&FF
        move.w  d0,d1
    4586:	|   move.w d0,d1
        add.w   d5,d1
    4588:	|   add.w d5,d1
        andi.w  #63,d1
    458a:	|   andi.w #63,d1
        add.w   d1,d1
    458e:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t1]
    4590:	|   move.w (0,a3,d1.w),d2
        move.b  d2,33(a1)             | byte33 = low byte
    4594:	|   move.b d2,33(a1)
        lsr.w   #8,d2
    4598:	|   lsr.w #8,d2
        move.b  d2,2(a1)              | byte2 = high byte
    459a:	|   move.b d2,2(a1)

