        move.w  d0,d1
    459e:	|   move.w d0,d1
        add.w   d4,d1
    45a0:	|   add.w d4,d1
        andi.w  #63,d1
    45a2:	|   andi.w #63,d1
        add.w   d1,d1
    45a6:	|   add.w d1,d1
        move.w  (a3,d1.w),d2           | d2 = tileDeco[t0]
    45a8:	|   move.w (0,a3,d1.w),d2
        move.b  d2,3(a1)              | byte3 = low byte
    45ac:	|   move.b d2,3(a1)
        lsr.w   #8,d2
    45b0:	|   lsr.w #8,d2
        move.b  d2,32(a1)             | byte32 = high byte
