        move.l  a4,a0
    468a:	movea.l a4,a0
        adda.l  d4,a0
    468c:	adda.l d4,a0
        movem.l (a0),d0-d1
    468e:	movem.l (a0),d0-d1
        movem.l d0-d1,(a1)              | store to PF2 plane 1
    4692:	movem.l d0-d1,(a1)

        | --- Plane 3 (BPL4): left border from border_data+1*8192 ---
        move.l  a4,a0
    4696:	movea.l a4,a0
        adda.l  #8192,a0
    4698:	adda.l #8192,a0
        adda.l  d4,a0
    469e:	adda.l d4,a0
        movem.l (a0),d0-d1
    46a0:	movem.l (a0),d0-d1
        movem.l d0-d1,(a2)              | store to PF2 plane 3
    46a4:	movem.l d0-d1,(a2)

