    46a8:	movea.l a4,a0
        adda.l  #16384,a0
    46aa:	adda.l #16384,a0
        adda.l  d4,a0
    46b0:	adda.l d4,a0
        movem.l (a0),d0-d1
    46b2:	movem.l (a0),d0-d1
        movem.l d0-d1,(a6)              | store to PF2 plane 5
    46b6:	movem.l d0-d1,(a6)

