        adda.l  d4,a0
    46d0:	adda.l d4,a0
        movem.l (a0),d0-d1
    46d2:	movem.l (a0),d0-d1
        movem.l d0-d1,32(a2)
    46d6:	movem.l d0-d1,32(a2)

        | Plane 5 (BPL6) right
        move.l  a5,a0
    46dc:	movea.l a5,a0
        adda.l  #16384,a0
    46de:	adda.l #16384,a0
        adda.l  d4,a0
    46e4:	adda.l d4,a0
        movem.l (a0),d0-d1
